"import asyncio\nfrom sqlalchemy import text\nfrom app.database import async_session\nimport traceback\n\nasync def check_rls():\n    results = []\n    try:\n        async with async_session() as session:\n            # Check if RLS is enabled on bookings table\n            res = await session.execute(text(\"SELECT relrowsecurity, relforcerowsecurity FROM pg_class WHERE relname = 'bookings'\"))\n            rls_status = res.fetchone()\n            if rls_status:\n                results.append(f\"Bookings RLS Enabled: {rls_status[0]}, Forced: {rls_status[1]}\")\n            else:\n                results.append(\"Table 'bookings' not found in pg_class.\")\n            \n            # List policies on bookings table\n            res = await session.execute(text(\"SELECT policyname FROM pg_policies WHERE tablename = 'bookings'\"))\n            policies = res.fetchall()\n            results.append(f\"Policies on bookings: {[p[0] for p in policies]}\")\n    except Exception as e:\n        results.append(f\"Error: {e}\\n{traceback.format_exc()}\")\n        \n    with open('scripts/check_rls_output.txt', 'w') as f:\n        f.write('\\n'.join(results))\n\nif __name__ == '__main__':\n    asyncio.run(check_rls())\n"
